#!/usr/bin/env node
import { program } from "commander";
import { uploadSourcemaps } from "./lib.js";

declare const __PACKAGE_VERSION__: string;

program
  .name("@middleware.io/sourcemap-uploader")
  .version(__PACKAGE_VERSION__)
  .description("Upload Javascript sourcemaps to Middleware")

program
  .command("upload")
  .requiredOption("-k, --apiKey <string>", "The Middleware rum api key")
  .option("-av, --appVersion [string]", "The current version of your deploy")
  .option(
    "-p, --path [string]",
    "Sets the directory of where the sourcemaps are (relative from where the command is run)",
    "."
  )
  .option(
    "-bu, --backendUrl [string]",
    "An optional backend url for self-hosted deployments"
  )
  .option(
    "-bp, --basePath [string]",
    "An optional base path for the sourcemaps to be uploaded to"
  )
  .option(
    "-d, --deleteAfterUpload [boolean]",
    "Delete the sourcemaps after uploading (default false)"
  )
  .action(uploadSourcemaps);

program.parse();

